  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"COE","domain_id":"information","opensat_index":1236,"opensat_domain":"Information and Ideas","opensat_raw_id":"random_id_21","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.901Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
